import constFlaskURL from '../hooks/constFlaskURL'
// Create.
export const addRow = async (endpoint, data, { headers={} }) => {
    await constFlaskURL.post(endpoint, data);
}
// Read.
export const readRows = async (enpoint, headers) => {
    try {
        await constFlaskURL.get(enpoint, headers);
    } catch (error) {
        console.error(error);
    }
}

export const getRow = async (endpoint, id_row) => {
    try {
        await constFlaskURL.get(`${endpoint}?id=${id_row}`);
    } catch (error) {
        console.error(error);
    } 
}
// Update.
export const updateRow = async (endpoint, id_row, data) => {
    try {
        await constFlaskURL.put(`${endpoint}?id=${id_row}`, data);
    } catch (error) {
        console.error(error);
    }
}
// Delete.
export const deleteRow = async (endpoint, id_row) => {
    try {
        await constFlaskURL.delete(`${endpoint}?id=${id_row}`);
    } catch (error) {
        console.error(error);
    } 
}
